# AUTO-style add: rockwool crop-steering terms.
GLOSSARY_ADD = [
    {"term": "Water content (WC%)", "defn": "The share of a block's or pot's volume that is water right now, as a percentage. In rockwool this single number is what you steer.", "tags": ["crop steering", "precision"]},
    {"term": "Recovery floor", "defn": "The lowest water content a rockwool block can reach and still rewet evenly from the dripper. Below it (around 25-30% WC) the fibre channels and the core stays dry.", "tags": ["crop steering"]},
    {"term": "Dryback %", "defn": "The size of a dryback, in percentage points of water content: the daily peak minus the next trough (e.g. 78% to 58% is a 20-point dryback).", "tags": ["crop steering"]},
    {"term": "Substrate EC", "defn": "The salt strength of the water inside the medium, where the roots are. Steer to this reading, not the dripper or drain EC.", "tags": ["crop steering", "precision"]},
]
